    for (let i = 0; i < n; ++i) {
        if (nums[i] !== 0) {
            nums[nonZeroIndex++] = nums[i];
        }
    }
    while(nonZeroIndex < n) {
        nums[nonZeroIndex++] = 0;
    }
    return nums;
}
